<?php function maxEnv($e){usort($e,fn($a,$b)=>$a[0]==$b[0]?$b[1]-$a[1]:$a[0]-$b[0]);$tails=[];foreach($e as $p){$lo=0;$hi=count($tails);while($lo<$hi){$m=intdiv($lo+$hi,2);if($tails[$m]<$p[1])$lo=$m+1;else$hi=$m;}if($lo==count($tails))$tails[]=$p[1];else$tails[$lo]=$p[1];}return count($tails);}$d=preg_split('/\s+/',trim(stream_get_contents(STDIN)));if(count($d)&&$d[0]!==""){$idx=0;$t=intval($d[$idx++]);$out=[];for($tc=0;$tc<$t;$tc++){$n=intval($d[$idx++]);$e=[];for($i=0;$i<$n;$i++)$e[]=[intval($d[$idx++]),intval($d[$idx++])];$out[]=strval(maxEnv($e));}echo implode("\n\n",$out);}
